const content = $input.first().json.message.content;

// Extract all `loc1`, `loc2`, etc., into an array
const urls = Object.values(content);

// Return each URL as a separate item
return urls.map(url => ({
  json: { url }
}));

const data = $('OpenAI1').first().json.message;

const content = data.content;

const urls = [];

Object.keys(content).forEach(key => {
  if (key.startsWith('loc')) {
    urls.push({ json: { url: content[key] } });
  }
});

return urls;

// Get all input items
const items = $input.all();

// Function to convert markdown to plain text
function convertMarkdownToPlainText(markdown) {
  // Ensure we're working with a string
  let plainText = String(markdown);

  // Remove links: [text](URL)
  plainText = plainText.replace(/\[([^\]]+)\]\([^\)]+\)/g, '$1');

  // Remove images: ![alt text](URL)
  plainText = plainText.replace(/!\[([^\]]*)\]\([^\)]+\)/g, '$1');

  // Remove headers: # Header
  plainText = plainText.replace(/(#+)\s*(.*)/g, '$2');

  // Remove bold and italic formatting
  plainText = plainText.replace(/\*\*|\*|__|_/g, '');

  // Remove HTML special characters
  plainText = plainText.replace(/([<>])/g, '');

  // Remove extra line breaks
  plainText = plainText.replace(/\n\s*\n/g, '\n');

  // Remove bullet points or numbered list formatting
  plainText = plainText.replace(/^\s*[-*+]\s+/gm, '');

  return plainText.trim();
}

// Process all items and combine them with page numbers and clear formatting
const combinedContent = items.map((item, index) => {
  let content;
  if (typeof item === 'object' && item !== null) {
    content = item.data || item.content || item.text || JSON.stringify(item);
  } else {
    content = String(item);
  }

  const pageNumber = index + 1;
  const processedContent = convertMarkdownToPlainText(content);

  return `Page ${pageNumber}\n──────────────────\n\n${processedContent}\n\n\n`;
}).join('\n\n'); // Double line breaks between pages

// Return with both raw content and formatted content
return [{
  json: {
    content: combinedContent,
    rawContent: items.map((item, index) => ({
      pageNumber: index + 1,
      content: convertMarkdownToPlainText(String(item.data || item.content || item.text || item))
    }))
  }
}];

function extractAllLocs(data) {
    const locs = [];

    function findLocs(obj) {
        if (!obj) return;

        // If it's an object, check for loc key and continue recursion
        if (typeof obj === 'object') {
            for (const key in obj) {
                if (key === 'loc' && typeof obj[key] === 'string') {
                    locs.push(obj[key]);
                } else {
                    findLocs(obj[key]);
                }
            }
        }
        // If it's an array, loop through each item
        else if (Array.isArray(obj)) {
            obj.forEach(findLocs);
        }
    }

    findLocs(data);
    return locs.map(url => ({ url }));
}

